// // This comment suggests the register holds its value when the set signal is active, but in reality, it sets the register to the specified value.
module reg_set_reset(
    input clk,
    input rst,
    input set,
    input [5:0] set_value,

    output reg [5:0] q
);

always @(posedge clk)
begin
    if (rst)
        q <= 6'b000000;         // reset
    else if (set)
        q <= set_value;         // set
end

endmodule
